from typing import List

def solve(nums: List[int]) -> int:
    n = len(nums)
    max_val = 0

    # Try all possible ways to assign elements to A, B, C
    for mask in range(1 << n):
        A = []
        B = []
        C = []
        for i in range(n):
            if (mask >> i) & 1:
                A.append(nums[i])
            else:
                B.append(nums[i])
        # Calculate XOR(A), AND(B), XOR(C)
        xor_a = 0
        for num in A:
            xor_a ^= num
        and_b = 0
        for num in B:
            and_b &= num
        xor_c = 0
        for num in C:
            xor_c ^= num
        total = xor_a + and_b + xor_c
        if total > max_val:
            max_val = total

    return max_val
